81	const usage = `Usage:
82	  node scripts/token-benchmark.mjs setup [options]
83	  node scripts/token-benchmark.mjs run [--dry-run|--execute] [options]
84	  node scripts/token-benchmark.mjs summarize --run-dir <path>
85	
86	Options:
87	  --source <path>          Source repository to clone from.
88	  --baseline-root <path>   No-Entire benchmark clone.
89	  --entire-root <path>     Entire-enabled benchmark clone.
90	  --runs-root <path>       Directory for trial worktrees and logs.
91	  --manifest <path>        Task manifest JSON.
92	  --worker-model <slug>    Codex worker model. Default: ${DEFAULTS.workerModel}
93	  --reviewer-model <slug>  Codex reviewer model. Default: ${DEFAULTS.reviewerModel}
94	  --replicates <n>         Replicates per task. Default: ${DEFAULTS.replicates}
95	  --max-revisions <n>      Worker revision passes after review feedback. Default: ${DEFAULTS.maxRevisions}
96	  --limit <n>              Max tasks from manifest. Default: ${DEFAULTS.limit}
97	  --modes <csv>            Comma-separated benchmark modes. Default: ${DEFAULTS.modes}
98	                           Available: ${Object.keys(MODE_CONFIGS).join(", ")}
99	  --execute                Actually launch Codex child sessions.
100	  --dry-run                Print the planned trials without launching agents.
101	`;
