103	function parseArgs(argv) {
104	  const args = [...argv];
105	  const command = args.shift();
106	  const opts = {
107	    ...DEFAULTS,
108	    command,
109	    execute: false,
110	    dryRun: false,
111	    runDir: "",
112	  };
113	
114	  for (let i = 0; i < args.length; i += 1) {
115	    const arg = args[i];
116	    const next = () => {
117	      i += 1;
118	      if (i >= args.length) {
119	        throw new Error(`Missing value for ${arg}`);
120	      }
121	      return args[i];
122	    };
123	
124	    switch (arg) {
125	      case "--source":
126	        opts.source = next();
127	        break;
128	      case "--baseline-root":
129	        opts.baselineRoot = next();
130	        break;
131	      case "--entire-root":
132	        opts.entireRoot = next();
133	        break;
134	      case "--runs-root":
135	        opts.runsRoot = next();
136	        break;
137	      case "--manifest":
138	        opts.manifest = next();
139	        break;
140	      case "--worker-model":
141	        opts.workerModel = next();
142	        break;
143	      case "--reviewer-model":
144	        opts.reviewerModel = next();
145	        break;
146	      case "--replicates":
147	        opts.replicates = Number.parseInt(next(), 10);
148	        break;
149	      case "--max-revisions":
150	        opts.maxRevisions = Number.parseInt(next(), 10);
151	        break;
152	      case "--limit":
153	        opts.limit = Number.parseInt(next(), 10);
154	        break;
155	      case "--modes":
156	        opts.modes = next();
157	        break;
158	      case "--run-dir":
159	        opts.runDir = next();
160	        break;
161	      case "--execute":
162	        opts.execute = true;
163	        break;
164	      case "--dry-run":
165	        opts.dryRun = true;
166	        break;
167	      case "-h":
168	      case "--help":
169	        console.log(usage);
170	        process.exit(0);
171	        break;
172	      default:
173	        throw new Error(`Unknown option: ${arg}`);
174	    }
175	  }
176	
177	  if (!command || !["setup", "run", "summarize"].includes(command)) {
178	    throw new Error(`Unknown or missing command.\n\n${usage}`);
179	  }
180	  if (opts.execute && opts.dryRun) {
181	    throw new Error("Choose only one of --execute or --dry-run.");
182	  }
183	  if (!opts.execute && opts.command === "run") {
184	    opts.dryRun = true;
185	  }
186	  if (!Number.isInteger(opts.replicates) || opts.replicates < 1) {
187	    throw new Error("--replicates must be a positive integer.");
188	  }
189	  if (!Number.isInteger(opts.maxRevisions) || opts.maxRevisions < 0) {
190	    throw new Error("--max-revisions must be zero or greater.");
191	  }
192	  if (!Number.isInteger(opts.limit) || opts.limit < 1) {
193	    throw new Error("--limit must be a positive integer.");
194	  }
195	  opts.modes = parseModes(opts.modes);
196	
197	  return opts;
198	}
199	
200	function parseModes(value) {
201	  const modes = String(value)
202	    .split(",")
203	    .map((mode) => mode.trim())
204	    .filter(Boolean);
205	  if (!modes.length) {
206	    throw new Error("--modes must include at least one mode.");
207	  }
208	  for (const mode of modes) {
209	    if (!MODE_CONFIGS[mode]) {
210	      throw new Error(`Unknown mode: ${mode}. Available modes: ${Object.keys(MODE_CONFIGS).join(", ")}`);
211	    }
212	  }
213	  return modes;
214	}
215	
216	function run(cmd, args, options = {}) {
217	  const pretty = [cmd, ...args].join(" ");
218	  if (options.dryRun) {
219	    console.log(`[dry-run] ${pretty}`);
220	    return { status: 0, stdout: "", stderr: "" };
221	  }
222	
223	  const result = spawnSync(cmd, args, {
224	    cwd: options.cwd,
225	    env: options.env,
226	    encoding: "utf8",
227	    shell: false,
228	    timeout: options.timeoutMs,
229	    maxBuffer: options.maxBuffer || 50 * 1024 * 1024,
230	  });
231	
232	  if (result.error && result.error.code !== "ETIMEDOUT") {
233	    throw result.error;
234	  }
235	
236	  const status = result.status ?? 1;
237	  if (options.logFile) {
238	    fs.mkdirSync(path.dirname(options.logFile), { recursive: true });
239	    fs.writeFileSync(
240	      options.logFile,
241	      [
242	        `$ ${pretty}`,
243	        "",
244	        "## stdout",
245	        result.stdout || "",
246	        "",
247	        "## stderr",
248	        result.stderr || "",
249	        "",
250	        `status=${status}`,
251	      ].join("\n"),
252	    );
253	  }
254	
255	  if (options.check !== false && status !== 0) {
256	    throw new Error(`Command failed (${status}): ${pretty}\n${result.stderr || result.stdout}`);
257	  }
258	
259	  return {
260	    status,
261	    stdout: result.stdout || "",
262	    stderr: result.stderr || "",
263	    timedOut: result.error?.code === "ETIMEDOUT",
264	  };
265	}
266	
267	function runShell(command, options = {}) {
268	  if (options.dryRun) {
269	    console.log(`[dry-run] ${command}`);
270	    return { status: 0, stdout: "", stderr: "" };
271	  }
272	
273	  const result = spawnSync(command, {
274	    cwd: options.cwd,
275	    env: options.env,
276	    encoding: "utf8",
277	    shell: true,
278	    timeout: options.timeoutMs,
279	    maxBuffer: options.maxBuffer || 50 * 1024 * 1024,
280	  });
281	  const status = result.status ?? 1;
282	
283	  if (options.logFile) {
284	    fs.mkdirSync(path.dirname(options.logFile), { recursive: true });
285	    fs.writeFileSync(
286	      options.logFile,
287	      [
288	        `$ ${command}`,
289	        "",
290	        "## stdout",
291	        result.stdout || "",
292	        "",
293	        "## stderr",
294	        result.stderr || "",
295	        "",
296	        `status=${status}`,
297	      ].join("\n"),
298	    );
299	  }
300	
301	  if (options.check !== false && status !== 0) {
302	    throw new Error(`Command failed (${status}): ${command}\n${result.stderr || result.stdout}`);
303	  }
304	
305	  return {
306	    status,
307	    stdout: result.stdout || "",
308	    stderr: result.stderr || "",
309	    timedOut: result.error?.code === "ETIMEDOUT",
310	  };
311	}
