313	function repoRoot() {
314	  return run("git", ["rev-parse", "--show-toplevel"], { cwd: process.cwd() }).stdout.trim();
315	}
316	
317	function resolveFromRepo(value) {
318	  if (path.isAbsolute(value)) {
319	    return value;
320	  }
321	  return path.join(repoRoot(), value);
322	}
