324	function cloneOrUpdate(source, dest, dryRun) {
325	  if (!fs.existsSync(dest)) {
326	    run("git", ["clone", source, dest], { dryRun });
327	    return;
328	  }
329	
330	  if (!fs.existsSync(path.join(dest, ".git"))) {
331	    throw new Error(`${dest} exists but is not a Git clone.`);
332	  }
333	
334	  run("git", ["fetch", "--all", "--tags"], { cwd: dest, dryRun });
335	}
336	
337	function setup(opts) {
338	  cloneOrUpdate(opts.source, opts.baselineRoot, opts.dryRun);
339	  cloneOrUpdate(opts.source, opts.entireRoot, opts.dryRun);
340	  alignOriginWithSource(opts.source, opts.baselineRoot, opts.dryRun);
341	  alignOriginWithSource(opts.source, opts.entireRoot, opts.dryRun);
342	
343	  run("entire", ["disable", "--force"], {
344	    cwd: opts.baselineRoot,
345	    dryRun: opts.dryRun,
346	    check: false,
347	  });
348	
349	  run("entire", ["agent", "add", "codex", "--force"], {
350	    cwd: opts.entireRoot,
351	    dryRun: opts.dryRun,
352	    check: false,
353	  });
354	
355	  console.log(`Baseline root: ${opts.baselineRoot}`);
356	  console.log(`Entire root:   ${opts.entireRoot}`);
357	}
358	
359	function alignOriginWithSource(source, dest, dryRun) {
360	  const sourceOrigin = run("git", ["config", "--get", "remote.origin.url"], {
361	    cwd: source,
362	    check: false,
363	    dryRun,
364	  }).stdout.trim();
365	  if (!sourceOrigin || sourceOrigin === source) {
366	    return;
367	  }
368	  run("git", ["remote", "set-url", "origin", sourceOrigin], { cwd: dest, dryRun });
369	  run("git", ["fetch", "origin", "--tags"], { cwd: dest, dryRun });
370	}
371	
372	function readTasks(manifestPath, limit) {
373	  const parsed = JSON.parse(fs.readFileSync(manifestPath, "utf8"));
374	  if (!Array.isArray(parsed)) {
375	    throw new Error("Task manifest must be a JSON array.");
376	  }
377	  return parsed.slice(0, limit);
378	}
