380	function shuffle(items) {
381	  const copy = [...items];
382	  for (let i = copy.length - 1; i > 0; i -= 1) {
383	    const j = crypto.randomInt(i + 1);
384	    [copy[i], copy[j]] = [copy[j], copy[i]];
385	  }
386	  return copy;
387	}
