389	function slugPart(value) {
390	  return String(value).replace(/[^a-zA-Z0-9._-]+/g, "-").replace(/^-|-$/g, "");
391	}
392	
393	function appendExclude(trialDir) {
394	  const exclude = run("git", ["rev-parse", "--git-path", "info/exclude"], {
395	    cwd: trialDir,
396	  }).stdout.trim();
397	  const additions = [
398	    "",
399	    "# token benchmark scaffolding",
400	    ".bench/",
401	    ".codex/",
402	    ".agents/",
403	    ".entire/settings.local.json",
404	    "node_modules/",
405	    "dist/",
406	  ].join("\n");
407	  fs.appendFileSync(exclude, `${additions}\n`);
408	}
