410	function createEntireShim(trialDir) {
411	  const binDir = path.join(trialDir, ".bench", "bin");
412	  fs.mkdirSync(binDir, { recursive: true });
413	  const shim = path.join(binDir, "entire");
414	  fs.writeFileSync(
415	    shim,
416	    [
417	      "#!/usr/bin/env bash",
418	      "echo 'Entire CLI is disabled in baseline benchmark mode.' >&2",
419	      "exit 127",
420	      "",
421	    ].join("\n"),
422	  );
423	  fs.chmodSync(shim, 0o755);
424	  return binDir;
425	}
