427	function prepareTrial(root, trialDir, task, mode, branch, dryRun) {
428	  const modeConfig = MODE_CONFIGS[mode];
429	  fs.mkdirSync(path.dirname(trialDir), { recursive: true });
430	  run("git", ["worktree", "add", "-B", branch, trialDir, task.base], {
431	    cwd: root,
432	    dryRun,
433	  });
434	  if (dryRun) {
435	    return { env: process.env };
436	  }
437	
438	  appendExclude(trialDir);
439	  fs.mkdirSync(path.join(trialDir, ".bench"), { recursive: true });
440	
441	  if (modeConfig.rootKind === "baseline") {
442	    run("entire", ["disable", "--force"], {
443	      cwd: trialDir,
444	      check: false,
445	    });
446	    const shimDir = createEntireShim(trialDir);
447	    return {
448	      env: {
449	        ...process.env,
450	        PATH: `${shimDir}${path.delimiter}${process.env.PATH}`,
451	        BENCH_MODE: mode,
452	      },
453	    };
454	  }
455	
456	  run("entire", ["agent", "add", "codex", "--force"], {
457	    cwd: trialDir,
458	    check: false,
459	  });
460	  return {
461	    env: {
462	      ...process.env,
463	      BENCH_MODE: mode,
464	    },
465	  };
466	}
