468	function maybeInstallDependencies(trialDir, benchDir, task, env) {
469	  if (!task.installDependencies) {
470	    return { status: 0, skipped: true };
471	  }
472	  return runShell("npm ci --prefer-offline --no-audit --fund=false", {
473	    cwd: trialDir,
474	    env,
475	    check: false,
476	    timeoutMs: 5 * 60 * 1000,
477	    logFile: path.join(benchDir, "npm-ci.log"),
478	  });
479	}
