485	function buildWorkerPrompt(task, mode, revision, feedbackPath) {
486	  const modeInstructions = MODE_CONFIGS[mode].instructions;
487	
488	  const revisionInstructions =
489	    revision === 0
490	      ? []
491	      : [
492	          "This is a revision pass after blind review feedback.",
493	          `Read the feedback at ${feedbackPath} and address it directly.`,
494	        ];
495	
496	  return [
497	    "# Benchmark Task",
498	    "",
499	    `Task ID: ${task.id}`,
500	    `Task kind: ${task.kind}`,
501	    "",
502	    "## Prompt",
503	    "",
504	    task.prompt,
505	    "",
506	    "## Acceptance Criteria",
507	    "",
508	    criteriaText(task),
509	    "",
510	    "## Mode Instructions",
511	    "",
512	    ...modeInstructions,
513	    "",
514	    "## Work Rules",
515	    "",
516	    "- Do not commit, push, or create a pull request.",
517	    "- Keep edits narrow and task-focused.",
518	    "- Run the most relevant checks yourself when useful.",
519	    "- In your final response, summarize the work and mention any checks run.",
520	    "",
521	    ...revisionInstructions,
522	    "",
523	  ].join("\n");
524	}
