526	function buildReviewerPrompt(task, artifacts) {
527	  return [
528	    "# Blind Benchmark Review",
529	    "",
530	    "Review the work against the task and acceptance criteria. Ignore how the work was produced.",
531	    "Return exactly one JSON object with this shape:",
532	    "",
533	    '{"verdict":"PASS|REVISE|FAIL","feedback":"short actionable feedback","confidence":0.0}',
534	    "",
535	    "Use PASS only if the output is useful and satisfies the criteria. Use REVISE for fixable gaps. Use FAIL for fundamentally wrong or missing work.",
536	    "",
537	    "## Task",
538	    "",
539	    task.prompt,
540	    "",
541	    "## Acceptance Criteria",
542	    "",
543	    criteriaText(task),
544	    "",
545	    "## Worker Final Message",
546	    "",
547	    artifacts.finalMessage || "(empty)",
548	    "",
549	    "## Git Diff",
550	    "",
551	    truncate(artifacts.diff || "(no diff)", 60000),
552	    "",
553	    "## Check Results",
554	    "",
555	    artifacts.checkSummary || "(no checks configured)",
556	    "",
557	  ].join("\n");
558	}
559	
560	function truncate(value, max) {
561	  if (value.length <= max) {
562	    return value;
563	  }
564	  return `${value.slice(0, max)}\n\n[truncated ${value.length - max} bytes]`;
565	}
566	
567	function codexExec({ trialDir, model, promptPath, jsonlPath, lastMessagePath, env, sandbox }) {
568	  fs.mkdirSync(path.dirname(jsonlPath), { recursive: true });
569	  const stderrPath = jsonlPath.replace(/\.jsonl$/, ".stderr.log");
570	
571	  const command = [
572	    "codex",
573	    "exec",
574	    "--cd",
575	    shellQuote(trialDir),
576	    "--model",
577	    shellQuote(model),
578	    "--sandbox",
579	    shellQuote(sandbox),
580	    "--json",
581	    "--output-last-message",
582	    shellQuote(lastMessagePath),
583	    "-",
584	    "<",
585	    shellQuote(promptPath),
586	    ">",
587	    shellQuote(jsonlPath),
588	  ].join(" ");
589	
590	  const result = runShell(command, {
591	    cwd: trialDir,
592	    env,
593	    check: false,
594	    timeoutMs: 45 * 60 * 1000,
595	    maxBuffer: 200 * 1024 * 1024,
596	  });
597	  fs.writeFileSync(stderrPath, result.stderr || "");
598	  return result;
599	}
600	
601	function shellQuote(value) {
602	  return `'${String(value).replaceAll("'", "'\\''")}'`;
603	}
604	
605	function runChecks(trialDir, benchDir, task, env, revision) {
606	  const checks = task.checks || [];
607	  const results = [];
608	  for (const [index, command] of checks.entries()) {
609	    const result = runShell(command, {
610	      cwd: trialDir,
611	      env,
612	      check: false,
613	      timeoutMs: 10 * 60 * 1000,
614	      logFile: path.join(benchDir, `check-${revision}-${index + 1}.log`),
615	    });
616	    results.push({
617	      command,
618	      status: result.status,
619	      timedOut: result.timedOut,
620	      log: `check-${revision}-${index + 1}.log`,
621	    });
622	  }
623	  return results;
624	}
625	
626	function checkSummary(checks) {
627	  if (!checks.length) {
628	    return "";
629	  }
630	  return checks
631	    .map((check) => `${check.status === 0 ? "PASS" : "FAIL"} ${check.command} (status ${check.status})`)
632	    .join("\n");
633	}
634	
635	function parseUsage(jsonlPath) {
636	  if (!fs.existsSync(jsonlPath)) {
637	    return emptyUsage();
638	  }
639	
640	  const lines = fs.readFileSync(jsonlPath, "utf8").split("\n").filter(Boolean);
641	  let latest = null;
642	  for (const line of lines) {
643	    try {
644	      const event = JSON.parse(line);
645	      if (event.type === "event_msg" && event.payload?.type === "token_count") {
646	        latest = normalizeUsage(event.payload.info?.total_token_usage) || latest;
647	      } else if (event.type === "turn.completed" && event.usage) {
648	        latest = normalizeUsage(event.usage) || latest;
649	      }
650	    } catch {
651	      // Ignore non-JSON output in a JSONL log.
652	    }
653	  }
654	  return latest || emptyUsage();
