657	function normalizeUsage(usage) {
658	  if (!usage) {
659	    return null;
660	  }
661	  const input = usage.input_tokens || 0;
662	  const output = usage.output_tokens || 0;
663	  return {
664	    input_tokens: input,
665	    cached_input_tokens: usage.cached_input_tokens || usage.cache_read_tokens || 0,
666	    output_tokens: output,
667	    reasoning_output_tokens: usage.reasoning_output_tokens || 0,
668	    total_tokens: usage.total_tokens || input + output,
669	  };
670	}
