685	    cached_input_tokens: (a.cached_input_tokens || 0) + (b.cached_input_tokens || 0),
686	    output_tokens: (a.output_tokens || 0) + (b.output_tokens || 0),
687	    reasoning_output_tokens: (a.reasoning_output_tokens || 0) + (b.reasoning_output_tokens || 0),
688	    total_tokens: (a.total_tokens || 0) + (b.total_tokens || 0),
689	  };
