692	function parseReviewerVerdict(lastMessagePath) {
693	  if (!fs.existsSync(lastMessagePath)) {
694	    return { verdict: "REVISE", feedback: "Reviewer produced no final message.", confidence: 0 };
695	  }
696	  const content = fs.readFileSync(lastMessagePath, "utf8").trim();
697	  const jsonText = extractJsonObject(content);
698	  if (!jsonText) {
699	    return {
700	      verdict: "REVISE",
701	      feedback: `Reviewer response was not parseable JSON: ${truncate(content, 1000)}`,
702	      confidence: 0,
703	    };
704	  }
705	  try {
706	    const parsed = JSON.parse(jsonText);
707	    const verdict = String(parsed.verdict || "REVISE").toUpperCase();
708	    return {
709	      verdict: ["PASS", "REVISE", "FAIL"].includes(verdict) ? verdict : "REVISE",
710	      feedback: String(parsed.feedback || ""),
711	      confidence: Number(parsed.confidence || 0),
712	    };
713	  } catch (error) {
