cd /tmp && rm -rf synth-run && mkdir -p synth-run/run1
# Build a synthetic run with two tasks x baseline/entire, where entire is cheaper on a history task, pricier on a code task.
node -e '
const fs=require("fs");const path=require("path");
const root="/tmp/synth-run/run1";
function tm(taskId,mode,rep,inTok,cached,out){
  const dir=path.join(root,taskId,`rep-${rep}`,mode);
  fs.mkdirSync(path.join(dir,".bench"),{recursive:true});
  const usage={input_tokens:inTok,cached_input_tokens:cached,output_tokens:out,reasoning_output_tokens:Math.round(out*0.3),total_tokens:inTok+out};
  const meta={taskId,mode,rep,trialDir:dir,workerModel:"gpt-5.5",reviewerModel:"gpt-5.4",
    finalVerdict:{verdict:"PASS"},revisions:[],workerUsage:usage,reviewerUsage:{input_tokens:1000,cached_input_tokens:0,output_tokens:200,reasoning_output_tokens:0,total_tokens:1200},
    workerMarginalApproxTokens:mode==="entire"?5000:0};
  fs.writeFileSync(path.join(dir,".bench","trial-meta.json"),JSON.stringify(meta,null,2));
  return {taskId,rep,mode,trialDir:dir,branch:"x",finalVerdict:meta.finalVerdict,workerUsage:usage,reviewerUsage:meta.reviewerUsage};
}
const trials=[];
// history task: entire cheaper (fewer fresh input tokens, more cached)
trials.push(tm("why-removed","baseline",1,800000,50000,40000));
trials.push(tm("why-removed","entire",1,500000,300000,30000));
trials.push(tm("why-removed","baseline",2,820000,40000,42000));
trials.push(tm("why-removed","entire",2,520000,310000,31000));
// code task: entire pricier
trials.push(tm("favicon","baseline",1,200000,10000,20000));
trials.push(tm("favicon","entire",1,260000,20000,24000));
const runMeta={runId:"run1",runDir:root,workerModel:"gpt-5.5",reviewerModel:"gpt-5.4",pricing:undefined,modes:["baseline","entire"],replicates:2,trials};
fs.writeFileSync(path.join(root,"run-meta.json"),JSON.stringify(runMeta,null,2));
console.log("synthetic run written");
'
echo "=== summarize ===" 
cd /tmp/entire-token-benchmark && node scripts/token-benchmark.mjs summarize --run-dir /tmp/synth-run/run1 2>&1

